def write_jsonl(path: Path) -> str:
    path.parent.mkdir(parents=True, exist_ok=True)
    text = "".join(json.dumps(row, sort_keys=True) + "\n" for row in ROWS)
    path.write_text(text, encoding="utf-8")
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def main() -> None:
    here = Path(__file__).resolve().parent
    out = here / "auto_interp_feature_tasks.jsonl"
    sha = write_jsonl(out)
    manifest_path = here / "MANIFEST.json"
    if manifest_path.exists():
        try:
            manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except Exception:
            manifest = {}
    else:
        manifest = {}
    manifest[out.name] = {
        "feature_types": dict(sorted(Counter(str(r.get("feature_type", "")) for r in ROWS).items())),
        "generator": Path(__file__).name,
        "gold_labels": dict(sorted(Counter(str(r.get("gold_label") or "null") for r in ROWS).items())),
        "rows": len(ROWS),
        "safety_notes": "benign synthetic snippets only; no model generation required",
        "sha256": sha,
        "verified_tokenizers": [],
    }
    manifest_path.write_text(json.dumps(manifest, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    print(f"wrote {out} ({len(ROWS)} rows, sha256={sha})")


if __name__ == "__main__":
    main()
